CREATE VIEW `ads_sr_user_wide_active_ed_view` (`dt` COMMENT "日期", `product_id` COMMENT "产品id", `user_id` COMMENT "用户id", `corever` COMMENT "core", `mt` COMMENT "mt", `ver` COMMENT "客户端版本号", `current_language` COMMENT "当前语言", `current_language2` COMMENT "注册语言", `reg_country` COMMENT "注册国家", `country_level` COMMENT "国家等级", `appver` COMMENT "app版本", `reg_time` COMMENT "注册时间", `reg_days` COMMENT "活跃留存天数", `sex` COMMENT "性别", `is_pay` COMMENT "历史是否付费 1：是 0：否", `is_pay_current` COMMENT "当天是否付费 1：是 0：否", `first_bookid` COMMENT "首次引流书籍", `book_code` COMMENT "书籍代号", `etl_time` COMMENT "数据清洗时间")
COMMENT "阅读线-用户活跃表，新增首次引流书籍，书籍代号" AS SELECT `dws`.`a`.`dt`, `dws`.`a`.`product_id`, `dws`.`a`.`user_id`, `dws`.`a`.`corever`, `dws`.`a`.`mt`, `dws`.`a`.`ver`, `dws`.`a`.`current_language`, `dws`.`a`.`current_language2`, `dws`.`a`.`reg_country`, `dws`.`a`.`country_level`, `dws`.`a`.`appver`, `dws`.`a`.`reg_time`, `dws`.`a`.`reg_days`, `dws`.`a`.`sex`, `dws`.`a`.`is_pay`, `dws`.`a`.`is_pay_current`, if((`b`.`first_bookid` = 0) OR (`b`.`first_bookid` IS NULL), 'other', `b`.`first_bookid`) AS `first_bookid`, if((`c`.`book_code` = '-') OR (`c`.`book_code` IS NULL), 'other', `c`.`book_code`) AS `book_code`, `dws`.`a`.`etl_time`
FROM `dws`.`dws_user_wide_active_ed` AS `a` LEFT OUTER JOIN (SELECT `dws`.`dws_user_market_channel_info_detail_td`.`product_id`, `dws`.`dws_user_market_channel_info_detail_td`.`user_id`, `dws`.`dws_user_market_channel_info_detail_td`.`mt`, `dws`.`dws_user_market_channel_info_detail_td`.`corever`, `dws`.`dws_user_market_channel_info_detail_td`.`lang2`, `dws`.`dws_user_market_channel_info_detail_td`.`first_bookid`
FROM `dws`.`dws_user_market_channel_info_detail_td`
WHERE (`dws`.`dws_user_market_channel_info_detail_td`.`dt` = (curdate())) AND (`dws`.`dws_user_market_channel_info_detail_td`.`product_id` != 6833)) `b` ON ((((`dws`.`a`.`product_id` = `b`.`product_id`) AND (`dws`.`a`.`user_id` = `b`.`user_id`)) AND (`dws`.`a`.`mt` = `b`.`mt`)) AND (`dws`.`a`.`corever` = `b`.`corever`)) AND (`dws`.`a`.`current_language2` = `b`.`lang2`) LEFT OUTER JOIN (SELECT `dim`.`dim_shuangwen_book_read_consume_info`.`book_id`, `dim`.`dim_shuangwen_book_read_consume_info`.`book_code`
FROM `dim`.`dim_shuangwen_book_read_consume_info`) `c` ON `b`.`first_bookid` = `c`.`book_id`;